const joinGroupMembership = `-- name: JoinGroupMembership :execrows
INSERT INTO group_memberships (
    group_id,
    user_id,
    role,
    joined_at
) VALUES ($1, $2, $3, $4)
ON CONFLICT (group_id, user_id) DO NOTHING
`

type JoinGroupMembershipParams struct {
	GroupID  uuid.UUID          `db:"group_id" json:"group_id"`
	UserID   uuid.UUID          `db:"user_id" json:"user_id"`
	Role     string             `db:"role" json:"role"`
	JoinedAt pgtype.Timestamptz `db:"joined_at" json:"joined_at"`
}

func (q *Queries) JoinGroupMembership(ctx context.Context, arg JoinGroupMembershipParams) (int64, error) {
	result, err := q.db.Exec(ctx, joinGroupMembership,
		arg.GroupID,
		arg.UserID,
		arg.Role,
		arg.JoinedAt,
	)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected(), nil
}

const listDirectChatMessages = `-- name: ListDirectChatMessages :many
SELECT
    m.id,
    m.chat_id,
    m.sender_user_id,
    m.kind,
    m.text_content,
    m.markdown_policy,
    m.created_at,
    m.updated_at,
    t.deleted_by_user_id,
    t.deleted_at,
    EXISTS (
        SELECT 1
        FROM direct_chat_pins AS p
        WHERE p.chat_id = m.chat_id AND p.message_id = m.id
    ) AS pinned
FROM direct_chat_messages AS m
JOIN direct_chat_participants AS self ON self.chat_id = m.chat_id
LEFT JOIN direct_chat_message_tombstones AS t ON t.message_id = m.id
WHERE self.user_id = $1 AND m.chat_id = $2
ORDER BY m.created_at DESC, m.id DESC
LIMIT $3
`

